import type { MapSpot } from '~/types/mapSpot'

export interface AdminTopic {
  id: number
  categorySlug: string
  categoryLabel: string
  topicKey: string
  topicLabel: string
  contentType: 'spots' | 'guide' | 'areas' | 'custom'
  spotFile: string | null
  maxSpots: number
  searchQueries: string[] | string
  bodySystemPrompt: string
  faqSystemPrompt: string
  enabled: boolean
  status: 'live' | 'coming-soon'
  icon: string | null
  accentColor: string | null
  pinColor: string | null
  standaloneUrl: string | null
  description: string | null
  updatedAt: string
}

export interface AdminCategory {
  slug: string
  title: string
  tagline: string
  icon: string
  color: string
  bgColor: string
  seoTitle: string
  seoDescription: string
}

export interface AdminRun {
  id: number
  categorySlug: string
  topicKey: string
  status: 'pending' | 'running' | 'completed' | 'failed'
  spotsGenerated: number | null
  tokensUsed: number | null
  startedAt: string
  completedAt: string | null
  outputPreview?: string
}

export function useAdminData() {
  const { data: categoriesData, refresh: refreshCategories } = useFetch<{
    categories: AdminCategory[]
  }>('/api/admin/site-categories')
  const { data: topicsData, refresh: refreshTopics } = useFetch<{ topics: AdminTopic[] }>(
    '/api/admin/content-pipeline/topics',
  )
  const { data: runsData, refresh: refreshRuns } = useFetch<{ runs: AdminRun[] }>(
    '/api/admin/content-pipeline/runs',
  )

  const categories = computed(() => categoriesData.value?.categories ?? [])
  const allTopics = computed(() => topicsData.value?.topics ?? [])
  const runs = computed(() => runsData.value?.runs ?? [])

  const fetchSpots = async (topicKey: string) => {
    return await $fetch<{ spots: MapSpot[] }>(`/api/admin/map-spots?contentType=${topicKey}`)
  }

  const saveCategory = async (category: Partial<AdminCategory>) => {
    return await $fetch('/api/admin/site-categories', {
      method: 'POST',
      body: category,
    })
  }

  const saveTopic = async (topic: Partial<AdminTopic>) => {
    return await $fetch('/api/admin/content-pipeline/topics', {
      method: 'POST',
      body: topic,
    })
  }

  const deleteTopic = async (id: number) => {
    return await $fetch('/api/admin/content-pipeline/topics', {
      method: 'DELETE',
      body: { id },
    })
  }

  const saveSpot = async (spot: Partial<MapSpot>) => {
    return await $fetch('/api/admin/map-spots', {
      method: 'POST',
      body: spot,
    })
  }

  const runPipeline = async (topicId: number) => {
    return await $fetch('/api/admin/content-pipeline/run', {
      method: 'POST',
      body: { topicId },
    })
  }

  const approveRun = async (runId: number, selectedSpotIds: string[]) => {
    return await $fetch('/api/admin/content-pipeline/approve', {
      method: 'POST',
      body: { runId, selectedSpotIds },
    })
  }

  const seedDefaults = async () => {
    return await $fetch('/api/admin/content-pipeline/seed', { method: 'POST' })
  }

  const generateDescription = async (topicLabel: string, categoryLabel: string) => {
    return await $fetch<{ description: string }>(
      '/api/admin/content-pipeline/generate-description',
      {
        method: 'POST',
        body: { topicLabel, categoryLabel },
      },
    )
  }

  const aiMagicSpots = async (spots: MapSpot[], topicLabel: string, categoryLabel: string) => {
    return await $fetch<{ spots: MapSpot[] }>('/api/admin/map-spots/ai-magic', {
      method: 'POST',
      body: { spots, topicLabel, categoryLabel },
    })
  }

  const smartSync = async () => {
    return await $fetch<{ success: boolean; updatedCount: number }>(
      '/api/admin/map-spots/smart-sync',
      {
        method: 'POST',
      },
    )
  }

  return {
    categories,
    refreshCategories,
    allTopics,
    refreshTopics,
    runs,
    refreshRuns,
    fetchSpots,
    saveCategory,
    saveTopic,
    deleteTopic,
    saveSpot,
    runPipeline,
    approveRun,
    seedDefaults,
    generateDescription,
    aiMagicSpots,
    smartSync,
  }
}

import { AUSTIN_BRIDGE_COORDINATES } from '~/data/bat-spots'

export const AUSTIN_TIME_ZONE = 'America/Chicago'

export interface ZonedDateParts {
  year: number
  month: number
  day: number
}

export interface SunsetComputation {
  dayOfYear: number
  sunsetMinutes: number
  sunsetDate: Date
}

function toRadians(degrees: number) {
  return degrees * (Math.PI / 180)
}

function toDegrees(radians: number) {
  return radians * (180 / Math.PI)
}

function clampMinutes(value: number) {
  if (!Number.isFinite(value)) {
    return 19 * 60
  }

  if (value < 0) {
    return 0
  }

  if (value > 1439) {
    return 1439
  }

  return value
}

function parseDatePart(parts: Intl.DateTimeFormatPart[], key: Intl.DateTimeFormatPartTypes) {
  return Number(parts.find(part => part.type === key)?.value || 0)
}

export function getTimeZoneOffsetMinutes(date: Date, timeZone: string) {
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hourCycle: 'h23',
  }).formatToParts(date)

  const year = parseDatePart(parts, 'year')
  const month = parseDatePart(parts, 'month')
  const day = parseDatePart(parts, 'day')
  const hour = parseDatePart(parts, 'hour')
  const minute = parseDatePart(parts, 'minute')
  const second = parseDatePart(parts, 'second')

  const interpretedUtc = Date.UTC(year, month - 1, day, hour, minute, second)
  return (interpretedUtc - date.getTime()) / 60000
}

export function getZonedDateParts(date: Date): ZonedDateParts {
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: AUSTIN_TIME_ZONE,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(date)

  return {
    year: parseDatePart(parts, 'year'),
    month: parseDatePart(parts, 'month'),
    day: parseDatePart(parts, 'day'),
  }
}

function getDayOfYear(parts: ZonedDateParts) {
  const utcStart = Date.UTC(parts.year, 0, 0)
  const utcCurrent = Date.UTC(parts.year, parts.month - 1, parts.day)
  return Math.floor((utcCurrent - utcStart) / 86400000)
}

export function localClockToDate(parts: ZonedDateParts, localMinutesFromMidnight: number) {
  const roundedMinutes = Math.round(localMinutesFromMidnight)
  const hour = Math.floor(roundedMinutes / 60)
  const minute = ((roundedMinutes % 60) + 60) % 60

  const localUtcLike = Date.UTC(parts.year, parts.month - 1, parts.day, hour, minute, 0)

  let offset = getTimeZoneOffsetMinutes(new Date(localUtcLike), AUSTIN_TIME_ZONE)
  let utcMillis = localUtcLike - offset * 60000

  offset = getTimeZoneOffsetMinutes(new Date(utcMillis), AUSTIN_TIME_ZONE)
  utcMillis = localUtcLike - offset * 60000

  return new Date(utcMillis)
}

export function calculateSunset(parts: ZonedDateParts): SunsetComputation {
  const dayOfYear = getDayOfYear(parts)

  const gamma = (2 * Math.PI / 365) * (dayOfYear - 1)
  const equationOfTime = 229.18 * (
    0.000075
    + 0.001868 * Math.cos(gamma)
    - 0.032077 * Math.sin(gamma)
    - 0.014615 * Math.cos(2 * gamma)
    - 0.040849 * Math.sin(2 * gamma)
  )

  const declination = 0.006918
    - 0.399912 * Math.cos(gamma)
    + 0.070257 * Math.sin(gamma)
    - 0.006758 * Math.cos(2 * gamma)
    + 0.000907 * Math.sin(2 * gamma)
    - 0.002697 * Math.cos(3 * gamma)
    + 0.00148 * Math.sin(3 * gamma)

  const latitudeRad = toRadians(AUSTIN_BRIDGE_COORDINATES.latitude)
  const zenith = toRadians(90.833)
  const hourAngle = Math.acos(
    (Math.cos(zenith) / (Math.cos(latitudeRad) * Math.cos(declination)))
    - (Math.tan(latitudeRad) * Math.tan(declination)),
  )

  const localNoonGuess = localClockToDate(parts, 12 * 60)
  const timezoneOffsetMinutes = getTimeZoneOffsetMinutes(localNoonGuess, AUSTIN_TIME_ZONE)
  const solarNoonMinutes = 720 - (4 * AUSTIN_BRIDGE_COORDINATES.longitude) - equationOfTime + timezoneOffsetMinutes
  const sunsetMinutes = clampMinutes(solarNoonMinutes + toDegrees(hourAngle) * 4)

  return {
    dayOfYear,
    sunsetMinutes,
    sunsetDate: localClockToDate(parts, sunsetMinutes),
  }
}

export function addMinutes(date: Date, minutes: number) {
  return new Date(date.getTime() + (minutes * 60000))
}

export function shiftAustinDate(parts: ZonedDateParts, days: number) {
  const noonUtc = Date.UTC(parts.year, parts.month - 1, parts.day + days, 12, 0, 0)
  return getZonedDateParts(new Date(noonUtc))
}

/**
 * Auth composable for Austin-Texas.net.
 *
 * Provides reactive `user`, `loggedIn`, and helper methods (`login`, `signup`,
 * `logout`, `refresh`). State is shared across the app via `useState`.
 *
 * Key: During SSR, $fetch to same-origin API routes must forward the
 * browser's cookies via `useRequestHeaders()`, otherwise the server-side
 * fetch won't have the auth cookie and the user will appear unauthenticated.
 */

interface AuthUser {
  id: string
  email: string
  name: string | null
  isAdmin: boolean
}

export function useAuth() {
  const user = useState<AuthUser | null>('auth-user', () => null)
  const initialized = useState<boolean>('auth-initialized', () => false)

  const loggedIn = computed(() => !!user.value)
  const isAdmin = computed(() => !!user.value?.isAdmin)

  /**
   * Fetch the current user from /api/auth/me.
   * Forwards cookies during SSR so the server-side request
   * has access to the auth cookie.
   */
  async function refresh() {
    try {
      // Forward browser cookies during SSR
      const headers = import.meta.server ? useRequestHeaders(['cookie']) : {}
      const res = await $fetch<{ user: AuthUser | null }>('/api/auth/me', { headers })
      user.value = res.user ?? null
    } catch {
      user.value = null
    }
    initialized.value = true
  }

  /**
   * Ensure auth state is loaded at least once.
   * Safe to call multiple times — only fetches on first call.
   */
  async function ensureLoaded() {
    if (!initialized.value) {
      await refresh()
    }
  }

  async function login(email: string, password: string) {
    const res = await $fetch<{ user: AuthUser }>('/api/auth/login', {
      method: 'POST',
      body: { email, password },
    })
    user.value = res.user
    initialized.value = true
    return res.user
  }

  async function signup(email: string, password: string, name?: string) {
    const res = await $fetch<{ user: AuthUser }>('/api/auth/signup', {
      method: 'POST',
      body: { email, password, name },
    })
    user.value = res.user
    initialized.value = true
    return res.user
  }

  async function logout() {
    await $fetch('/api/auth/logout', { method: 'POST', body: {} })
    user.value = null
  }

  return {
    user: readonly(user) as Readonly<Ref<AuthUser | null>>,
    loggedIn,
    isAdmin,
    login,
    signup,
    logout,
    refresh,
    ensureLoaded,
  }
}

/**
 * useMapKit — lazy-load Apple MapKit JS and initialize with a JWT token.
 *
 * Token source (in order):
 * 1. runtimeConfig.public.mapkitToken (MAPKIT_TOKEN) if set
 * 2. Else GET /api/mapkit-token — server signs a JWT for this origin (localhost or production)
 *
 * For local dev without a 7-day portal token: set APPLE_SECRET_KEY, APPLE_TEAM_ID, APPLE_KEY_ID
 * (same as Server API). Create a Maps identifier and key with MapKit JS in Apple Developer.
 */

declare const mapkit: any

const MAPKIT_SRC = 'https://cdn.apple-mapkit.com/mk/5.x.x/mapkit.js'

/** Shared singleton so multiple components don't double-load */
let initPromise: Promise<typeof mapkit> | null = null

function loadScript(): Promise<void> {
  return new Promise((resolve, reject) => {
    if (!import.meta.client) {
      resolve()
      return
    }
    if (import.meta.client) {
      if (document.querySelector(`script[src="${MAPKIT_SRC}"]`)) {
        resolve()
        return
      }
      const script = document.createElement('script')
      script.src = MAPKIT_SRC
      script.crossOrigin = 'anonymous'
      script.onload = () => resolve()
      script.onerror = () => reject(new Error('Failed to load MapKit JS'))
      document.head.appendChild(script)
    } else {
      resolve()
    }
  })
}

function isJwtExpired(token: string): boolean {
  try {
    const payload = JSON.parse(atob(token.split('.')[1]!))
    return typeof payload.exp === 'number' && payload.exp < Date.now() / 1000
  } catch {
    return true
  }
}

function fetchDynamicToken(): Promise<string> {
  return $fetch<{ token: string }>('/api/mapkit-token').then(({ token }) => token)
}

export function useMapKit() {
  const ready = ref(false)
  const error = ref<string | null>(null)
  const runtimeConfig = useRuntimeConfig()
  const staticToken = (runtimeConfig.public.mapkitToken as string) || ''

  if (import.meta.server) {
    return { mapkitReady: readonly(ready), mapkitError: readonly(error) }
  }

  if (!initPromise) {
    initPromise = loadScript().then(() => {
      const authorizationCallback = (done: (token: string) => void) => {
        if (staticToken && !isJwtExpired(staticToken)) {
          done(staticToken)
          return
        }
        fetchDynamicToken()
          .then(done)
          .catch((e) => {
            error.value = e?.message || 'Failed to load MapKit token'
            done('')
          })
      }
      mapkit.init({ authorizationCallback })
      return mapkit
    })
  }

  initPromise
    .then(() => {
      ready.value = true
      if (import.meta.client) {
        document.documentElement.dataset.mapkitLoaded = 'true'
      }
    })
    .catch((err) => {
      error.value = err instanceof Error ? err.message : 'MapKit JS init failed'
    })

  return { mapkitReady: readonly(ready), mapkitError: readonly(error) }
}

/**
 * Returns a function to resolve the MapKit JWT (static from config or from /api/mapkit-token).
 * Use this in components that need the token without going through useMapKit() init.
 */
export function useMapkitToken() {
  const runtimeConfig = useRuntimeConfig()
  const staticToken = String(runtimeConfig.public.mapkitToken || '')

  async function getMapkitToken(): Promise<string> {
    if (staticToken && !isJwtExpired(staticToken)) return staticToken
    return fetchDynamicToken()
  }

  return { getMapkitToken }
}

/**
 * Severity levels for Austin pollen data.
 *
 * Single source of truth for severity labels, colors, and thresholds.
 * Used across pollen components and pages.
 */

export type SeverityLevel = 'Low' | 'Medium' | 'High' | 'Very High' | 'Severe'

export interface SeverityInfo {
  level: SeverityLevel
  color: string
  range: string
  description: string
}

/**
 * Severity color map — maps level names to hex colors.
 * Also handles aliases (None, Very Low, Moderate, N/A).
 */
const SEVERITY_COLORS: Record<string, string> = {
  'None': '#64748B',
  'Very Low': '#22C55E',
  'Low': '#22C55E',
  'Medium': '#EAB308',
  'Moderate': '#EAB308',
  'High': '#F97316',
  'Very High': '#EF4444',
  'Severe': '#A855F7',
}

const FALLBACK_COLOR = '#9CA3AF'

/** Accent color used for generic pollen metrics (e.g., trend line) */
export const POLLEN_ACCENT = '#10B981'

/**
 * Get the hex color for a severity level.
 *
 * @param level - Severity level string (Low, Medium, High, Very High, Severe, etc.)
 * @returns Hex color string
 */
export function severityColor(level: string): string {
  return SEVERITY_COLORS[level] ?? FALLBACK_COLOR
}

/**
 * Get severity level + color from a raw grain count.
 *
 * @param count - Pollen grains per cubic meter
 * @returns Object with level name and hex color
 */
export function severityFromCount(count: number): { level: SeverityLevel; color: string } {
  if (count < 50) return { level: 'Low', color: SEVERITY_COLORS['Low']! }
  if (count < 500) return { level: 'Medium', color: SEVERITY_COLORS['Medium']! }
  if (count < 1500) return { level: 'High', color: SEVERITY_COLORS['High']! }
  if (count < 5000) return { level: 'Very High', color: SEVERITY_COLORS['Very High']! }
  return { level: 'Severe', color: SEVERITY_COLORS['Severe']! }
}

/**
 * The full severity scale — used for legend/about pages.
 */
export const SEVERITY_SCALE: SeverityInfo[] = [
  { level: 'Low', range: '0 – 50', color: SEVERITY_COLORS['Low']!, description: 'Minimal pollen. Most people unaffected.' },
  { level: 'Medium', range: '50 – 500', color: SEVERITY_COLORS['Medium']!, description: 'Moderate. Sensitive individuals may notice symptoms.' },
  { level: 'High', range: '500 – 1,500', color: SEVERITY_COLORS['High']!, description: 'High levels. Allergy sufferers should limit outdoor time.' },
  { level: 'Very High', range: '1,500 – 5,000', color: SEVERITY_COLORS['Very High']!, description: 'Very high. Stay indoors if possible. Keep windows closed.' },
  { level: 'Severe', range: '5,000+', color: SEVERITY_COLORS['Severe']!, description: 'Extreme levels. Avoid outdoor activity.' },
]

/**
 * KXAN Pollen Data Scraper
 *
 * Parses the KXAN allergy JS embed at:
 *   https://media.psg.nexstardigital.net/kxan/weather/allergy/yesterday_allergy_v8.js
 *
 * This endpoint returns a JS document.write() containing:
 * - var aryCedar = [ { y: ..., a: <count> }, ... ]
 * - var aryElm   = [ { y: ..., a: <count> }, ... ]
 * - var aryMold  = [ { y: ..., a: <count> }, ... ]
 * - HTML blocks with severity labels like "Cedar - Very high"
 * - A data-runtime timestamp
 *
 * All counts are in grains/m³ (real measurements from Georgetown Allergy & Asthma Center)
 */

export interface KxanAllergenHistory {
  date: string   // YYYY-MM-DD
  count: number  // grains/m³
}

export interface KxanPollenData {
  cedar: KxanAllergenHistory[]
  elm: KxanAllergenHistory[]
  mold: KxanAllergenHistory[]
  levels: {
    cedar: string   // "Very high", "High", "Medium", "Low"
    elm: string
    mold: string
  }
  reportDate: string  // YYYY-MM-DD
  lastFetched: string // ISO timestamp
}

const KXAN_URL = 'https://media.psg.nexstardigital.net/kxan/weather/allergy/yesterday_allergy_v8.js'

/**
 * Fetch and parse the KXAN pollen data endpoint
 */
export async function scrapeKxanPollen(): Promise<KxanPollenData> {
  const cacheBust = Date.now()
  const response = await fetch(`${KXAN_URL}?v=${cacheBust}`)

  if (!response.ok) {
    throw new Error(`KXAN fetch failed: ${response.status} ${response.statusText}`)
  }

  const jsText = await response.text()
  return parseKxanJs(jsText)
}

/**
 * Parse the JS content from KXAN into structured data
 */
export function parseKxanJs(jsText: string): KxanPollenData {
  const cedar = parseAllergenArray(jsText, 'aryCedar')
  const elm = parseAllergenArray(jsText, 'aryElm')
  const mold = parseAllergenArray(jsText, 'aryMold')

  // Extract severity levels from HTML: "Cedar - Very high", "Elm - Low", etc.
  const levels = {
    cedar: extractLevel(jsText, 'Cedar'),
    elm: extractLevel(jsText, 'Elm'),
    mold: extractLevel(jsText, 'Mold'),
  }

  // Extract report date from data-runtime or h3 content
  const dateMatch = jsText.match(/data-runtime="(\d{4}-\d{2}-\d{2})/)
    || jsText.match(/(January|February|March|April|May|June|July|August|September|October|November|December)\s+\d{1,2},\s+\d{4}/)
  let reportDate = new Date().toISOString().split('T')[0] as string
  if (dateMatch) {
    if (dateMatch[0].includes('data-runtime') && dateMatch[1]) {
      reportDate = dateMatch[1]
    } else {
      const d = new Date(dateMatch[0])
      if (!Number.isNaN(d.getTime())) {
        reportDate = d.toISOString().split('T')[0] as string
      }
    }
  }

  return {
    cedar,
    elm,
    mold,
    levels,
    reportDate,
    lastFetched: new Date().toISOString(),
  }
}

/**
 * Parse one allergen array (aryCedar, aryElm, aryMold) from the JS text
 *
 * Format: { y: new Date('2026/01/09').toLocaleDateString('en-US', options), a: 328 }
 * We extract the date string and the `a:` count value.
 */
function parseAllergenArray(jsText: string, varName: string): KxanAllergenHistory[] {
  // Find the array block — varName is internally controlled (aryCedar/aryElm/aryMold)
  // eslint-disable-next-line security/detect-non-literal-regexp
  const arrayRegex = new RegExp(`var ${varName}\\s*=\\s*\\[([\\s\\S]*?)\\];`, 'm')
  const match = jsText.match(arrayRegex)
  if (!match) return []

  const arrayContent = match[1]!
  const entries: KxanAllergenHistory[] = []

  // Match each entry: new Date('2026/01/09') ... a: 328
  const entryRegex = /new Date\('(\d{4}\/\d{2}\/\d{2})'\)[^}]*a:\s*(\d+)/g
  let entryMatch: RegExpExecArray | null
  while ((entryMatch = entryRegex.exec(arrayContent)) !== null) {
    const dateStr = entryMatch[1]?.replace(/\//g, '-') ?? '' // 2026/01/09 → 2026-01-09
    const count = Number.parseInt(entryMatch[2] ?? '0', 10)
    if (dateStr) entries.push({ date: dateStr, count })
  }

  return entries
}

/**
 * Extract severity level text from the HTML block
 * Looks for patterns like: "Cedar - Very high" in the allergen_value div
 */
function extractLevel(jsText: string, allergen: string): string {
  // Pattern: <div class="allergen_value">Cedar - Very high</div>
  // allergen is internally controlled (Cedar/Elm/Mold)
  // eslint-disable-next-line security/detect-non-literal-regexp
  const regex = new RegExp(`allergen_value[^>]*>\\s*${allergen}\\s*-\\s*([^<]+)<`, 'i')
  const match = jsText.match(regex)
  if (match?.[1]) {
    return match[1].trim()
  }
  return 'Unknown'
}
